CREATE TABLE learning_assignment(id BIGINT PRIMARY KEY AUTO_INCREMENT,reviewer_id VARCHAR(64) NOT NULL,course_code VARCHAR(80) NOT NULL,error_type VARCHAR(80) NOT NULL,status VARCHAR(32) NOT NULL,attempts INT NOT NULL DEFAULT 0,best_score DECIMAL(5,2) NOT NULL DEFAULT 0,due_at TIMESTAMP(6) NOT NULL,applied_at TIMESTAMP(6),version BIGINT NOT NULL DEFAULT 0);CREATE INDEX idx_learning_reviewer ON learning_assignment(reviewer_id,status);
